const functions = require('firebase-functions');
const { Client } = require('@sendgrid/client');
const twilio = require('twilio');

// Load environment variables from Cloud Secret Manager
const { SENDGRID_API_KEY, SENDGRID_FROM_EMAIL, TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, TWILIO_PHONE_NUMBER } =
  functions.config().secret;

// Set up SendGrid client with API key authentication
const sendgridClient = new Client(SENDGRID_API_KEY);

// Define a function to send an email via SendGrid
exports.sendEmail = async (event) => {
  try {
    const { to, subject, text } = event.data;
    const message = {
      from: SENDGRID_FROM_EMAIL,
      to,
      subject,
      text,
    };

    await sendgridClient.emptyRequest()
      .post('/v3/mail/send', { body: message })
      .then((response) => console.log(response))
      .catch((error) => console.error(error));

    return {
      statusCode: 200,
      body: JSON.stringify({ message: 'Email sent successfully' }),
    };
  } catch (error) {
    console.error(error);
    return {
      statusCode: 500,
      body: JSON.stringify({ message: 'Error sending email' }),
    };
  }
};

// Define a function to send an SMS via Twilio
exports.sendSms = async (event) => {
  try {
    const { to, message } = event.data;
    const accountSid = TWILIO_ACCOUNT_SID;
    const authToken = TWILIO_AUTH_TOKEN;

    const client = new twilio(accountSid, authToken);

    await client.messages.create({
      from: TWILIO_PHONE_NUMBER,
      to,
      body: message,
    })
      .then((message) => console.log(message.sid))
      .catch((error) => console.error(error));

    return {
      statusCode: 200,
      body: JSON.stringify({ message: 'SMS sent successfully' }),
    };
  } catch (error) {
    console.error(error);
    return {
      statusCode: 500,
      body: JSON.stringify({ message: 'Error sending SMS' }),
    };
  }
};